import threading

counter = 0

def increment():
    global counter
    for _ in range(100_000):
        # NOT atomic: LOAD_GLOBAL + BINARY_ADD + STORE_GLOBAL
        # GIL can be released between LOAD and STORE
        counter += 1

threads = [threading.Thread(target=increment) for _ in range(4)]
for t in threads: t.start()
for t in threads: t.join()

print(counter)  # Usually < 400_000 due to race conditions
# Fix: use threading.Lock() or collections.Counter with atomic ops
